INSERT INTO snow.tour_group_details (id, group_id, highlights, itinerary_text, cost_includes, cost_excludes, booking_notes, images_json, status, create_time, update_time) VALUES (1, 1, '<p>亮点： - 经典冰雪线路，一次打卡多地 - 赠送滑雪体验（以当天雪场开放为准） - 夜游雪乡（天气/交通可能调整）</p>', '<p><strong>行程概览</strong></p><p>D1 抵达后自由活动</p><p>D2 哈尔滨市区/冰雪主题景点</p><p>D3 雪乡全天</p><p>D4 亚布力滑雪</p><p>D5 返程</p>', '<p>费用包含：车辆、酒店、导游服务、部分门票（以出团通知为准）</p>', '<p>费用不含：个人消费、单房差、部分景区内小交通</p>', '<p>预订须知：请携带有效证件；冬季注意保暖；如遇极端天气可能调整行程。</p>', '[{"alt": "", "path": "https://images.unsplash.com/photo-1489599849927-2ee91cede3ba?auto=format&fit=crop&w=1200&q=80", "sort": 1}, {"alt": "", "path": "https://images.unsplash.com/photo-1542704792-e30dac463c90?auto=format&fit=crop&w=1200&q=80", "sort": 2}, {"alt": "", "path": "/profile/upload/2026/04/25/pexels-andyhvu-3244513_20260425223556A001.jpg", "sort": 3}]', '0', '2026-04-25 21:01:16', '2026-04-25 22:36:02');
INSERT INTO snow.tour_group_details (id, group_id, highlights, itinerary_text, cost_includes, cost_excludes, booking_notes, images_json, status, create_time, update_time) VALUES (2, 2, '<p>亮点： - 小团慢游，节奏更舒适 - 温泉放松+雾凇观赏 - 酒店升级（以实际库存为准）</p>', '<p><strong>行程概览</strong></p><p>D1 集合出发</p><p>D2 长白山景区</p><p>D3 温泉/雾凇</p><p>D4 返程</p>', '<p>费用包含：用车、酒店、导游/司兼导、基础保险</p>', '<p>费用不含：个人消费、餐食（若未包含）、部分二消项目</p>', '<p>预订须知：如需泡温泉请自备泳衣；高海拔/低温请注意身体状况。</p>', '[{"alt": "", "path": "https://images.unsplash.com/photo-1441974231531-c6227db76b6e?auto=format&fit=crop&w=1200&q=80", "sort": 1}, {"alt": "", "path": "https://images.unsplash.com/photo-1519681393784-d120267933ba?auto=format&fit=crop&w=1200&q=80", "sort": 2}]', '0', '2026-04-25 21:01:16', '2026-04-26 14:34:18');
INSERT INTO snow.tour_group_details (id, group_id, highlights, itinerary_text, cost_includes, cost_excludes, booking_notes, images_json, status, create_time, update_time) VALUES (3, 3, '<p>亮点： - 历史人文讲解更深入 - 轻松行程，适合亲子/长辈 - 城市美食自由探索</p>', '<p><strong>行程概览</strong></p><p>D1 沈阳历史文化</p><p>D2 前往丹东+江景</p><p>D3 返程</p>', '<p>费用包含：用车、住宿、导游服务</p>', '<p>费用不含：餐食、个人消费、部分门票</p>', '<p>预订须知：部分场馆需提前预约；请遵守当地参观规定。</p>', '[{"alt": "", "path": "/profile/upload/2026/04/25/屏幕截图 2026-04-25 225616_20260425225638A003.png", "sort": 1}]', '0', '2026-04-25 21:01:16', '2026-04-25 22:57:15');
INSERT INTO snow.tour_group_details (id, group_id, highlights, itinerary_text, cost_includes, cost_excludes, booking_notes, images_json, status, create_time, update_time) VALUES (4, 4, '<p>亮点： - 极寒体验与打卡 - 星空摄影氛围感 - 北极村地标合影</p>', '<p><strong>行程概览</strong></p><p>D1 抵达漠河</p><p>D2 北极村深度</p><p>D3 返程</p>', '<p>费用包含：用车、住宿、导游服务</p>', '<p>费用不含：个人消费、餐食、保暖装备租赁</p>', '<p>预订须知：极寒环境请做好保暖；部分体验受天气影响。</p>', '[{"alt": "", "path": "https://images.unsplash.com/photo-1482192596544-9eb780fc7f66?auto=format&fit=crop&w=1200&q=80", "sort": 1}, {"alt": "", "path": "https://images.unsplash.com/photo-1459478309853-2c33a60058e7?auto=format&fit=crop&w=1200&q=80", "sort": 2}]', '0', '2026-04-25 21:01:16', '2026-04-26 14:35:06');
